html: <!-- Starter HTML -->
<html>
  <head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Modal Entrance Animation</title>
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/tailwindcss/2.2.19/tailwind.min.css">
  </head>
  <body>
    <!-- Overlay Background -->
    <div id="overlay" class="fixed top-0 left-0 w-full h-screen bg-gray-900 bg-opacity-50 z-10"></div>
    <!-- Modal Container -->
    <div id="modal" class="fixed top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 z-20 bg-white p-4 rounded-md shadow-md max-w-md mx-auto" style="display: none;">
      <h2 class="text-lg font-bold mb-4">Modal Title</h2>
      <p class="text-gray-600 text-sm mb-4">Modal content goes here...</p>
      <button id="close-modal" class="px-4 py-2 bg-red-500 hover:bg-red-600 text-white rounded">Close</button>
    </div>
    <button id="open-modal" class="px-4 py-2 bg-blue-500 hover:bg-blue-600 text-white rounded">Open Modal</button>
    <script src="script.js"></script>
  </body>
</html>
css: #modal {
    animation: slideIn 1s ease-out forwards;
  }

  #modal.show {
    animation: slideIn 1s ease-out forwards;
  }

  @keyframes slideIn {
    from { transform: translateY(-100vh); }
    to { transform: translate(0, 0); }
  }

  #overlay {
    animation: fadeOut 1s ease-out forwards;
  }

  #overlay.show {
    animation: fadeIn 1s ease-out forwards;
  }

  @keyframes fadeIn {
    from { opacity: 0; }
    to { opacity: 0.5; }
  }

  @keyframes fadeOut {
    from { opacity: 0.5; }
    to { opacity: 0; }
  }
  #close-modal {
    position: absolute;
    top: 4px;
    right: 4px;
  }
js: <!-- Starter JS -->
<script>
  // Get elements
  const openModalButton = document.getElementById('open-modal');
  const closeModalButton = document.getElementById('close-modal');
  const modal = document.getElementById('modal');
  const overlay = document.getElementById('overlay');

  // Add event listeners
  openModalButton.addEventListener('click', () => {
    modal.classList.add('show');
    overlay.classList.add('show');
  });

  closeModalButton.addEventListener('click', () => {
    modal.classList.remove('show');
    overlay.classList.remove('show');
  });

  // Add a function to close the modal when the overlay is clicked
  overlay.addEventListener('click', () => {
    modal.classList.remove('show');
    overlay.classList.remove('show');
  });
</script>
